import type { QuizQuestion } from './quizzes'

export const quizzes2: Record<number, QuizQuestion[]> = {
  12: [
    { id: 'q12_1', question: 'Quelle est la plage de VLAN IDs utilisables sur un switch Cisco ?', options: ['VLAN 0 a 4095', 'VLAN 1 a 4094', 'VLAN 1 a 1005', 'VLAN 2 a 4094'], correct: 1, explanation: 'Les VLAN IDs valides vont de 1 a 4094. Le VLAN 0 est reserve au niveau systeme et le VLAN 4095 est reserve par la norme IEEE 802.1Q. Le VLAN 1 est le VLAN par defaut et ne peut pas etre supprime.' },
    { id: 'q12_2', question: 'Quel champ est insere dans une trame Ethernet par le protocole 802.1Q sur un lien trunk ?', options: ['Un champ de 2 octets contenant le numero de VLAN', 'Un tag de 4 octets entre l\'adresse source et le champ Type/Length', 'Un en-tete IP supplementaire de 20 octets', 'Un CRC additionnel de 4 octets en fin de trame'], correct: 1, explanation: 'Le tag 802.1Q fait 4 octets et est insere entre l\'adresse MAC source et le champ EtherType. Il contient le TPID (0x8100 sur 2 octets) et le TCI (Priority, DEI, VID sur 2 octets) dont 12 bits pour le VLAN ID.' },
    { id: 'q12_3', question: 'Quel est le role du VLAN natif sur un lien trunk 802.1Q ?', options: ['Il chiffre les trames sensibles avant de les envoyer sur le trunk', 'Il transporte les trames non taguees sans ajout de tag 802.1Q', 'Il bloque tout trafic non autorise sur le trunk', 'Il assure la redondance du lien trunk en cas de panne'], correct: 1, explanation: 'Le VLAN natif (VLAN 1 par defaut) transporte les trames sans tag 802.1Q. Si un switch recoit une trame non taguee sur un trunk, il l\'associe au VLAN natif. Il est recommande de changer le VLAN natif par defaut pour des raisons de securite.' },
    { id: 'q12_4', question: 'Quelle commande configure un port de switch en mode access pour le VLAN 10 ?', options: ['switchport mode trunk / switchport trunk allowed vlan 10', 'switchport mode access / switchport access vlan 10', 'vlan 10 / interface access', 'switchport vlan 10 mode access'], correct: 1, explanation: 'On configure d\'abord le port en mode access avec "switchport mode access", puis on assigne le VLAN avec "switchport access vlan 10". Un port access appartient a un seul VLAN et envoie des trames non taguees.' },
    { id: 'q12_5', question: 'Quel protocole Cisco negocie automatiquement la formation d\'un trunk entre deux switches ?', options: ['VTP (VLAN Trunking Protocol)', 'DTP (Dynamic Trunking Protocol)', 'STP (Spanning Tree Protocol)', 'CDP (Cisco Discovery Protocol)'], correct: 1, explanation: 'DTP (Dynamic Trunking Protocol) est un protocole proprietaire Cisco qui negocie automatiquement si un lien doit etre en mode trunk ou access. Il est recommande de le desactiver avec "switchport nonegotiate" pour des raisons de securite.' },
    { id: 'q12_6', question: 'Que se passe-t-il si le VLAN natif est different des deux cotes d\'un lien trunk ?', options: ['Le trunk refuse de s\'etablir et le lien reste inactif', 'Les trames non taguees sont placees dans le mauvais VLAN, causant des problemes de connectivite', 'Le switch corrige automatiquement la difference de VLAN natif', 'Rien, le VLAN natif n\'a pas besoin d\'etre identique'], correct: 1, explanation: 'Un mismatch de VLAN natif provoque des erreurs car les trames non taguees envoyees par un switch (VLAN natif X) sont interpretees dans un autre VLAN (VLAN natif Y) par le switch oppose. CDP/LLDP genere des alertes de native VLAN mismatch.' },
    { id: 'q12_7', question: 'Quelle commande limite les VLANs autorises sur un lien trunk ?', options: ['switchport trunk native vlan 10,20,30', 'switchport trunk allowed vlan 10,20,30', 'switchport allowed vlan add 10,20,30', 'trunk vlan filter 10,20,30'], correct: 1, explanation: 'La commande "switchport trunk allowed vlan 10,20,30" restreint le trunk aux VLANs specifies. Par defaut, tous les VLANs (1-4094) sont autorises. On peut aussi utiliser "add", "remove", "except" et "all" pour modifier la liste.' },
    { id: 'q12_8', question: 'Quel est le VLAN par defaut sur les switches Cisco et que peut-on faire avec ?', options: ['VLAN 0, il peut etre renomme mais pas supprime', 'VLAN 1, il ne peut etre ni supprime ni desactive', 'VLAN 100, il est reserve a la gestion et peut etre supprime', 'VLAN 1001, c\'est un VLAN etendu modifiable'], correct: 1, explanation: 'Le VLAN 1 est le VLAN par defaut sur tous les switches Cisco. Tous les ports y sont assignes initialement. Il ne peut etre ni supprime ni desactive. C\'est pourquoi il est recommande de creer un VLAN de gestion separe et un VLAN natif different de 1.' },
    { id: 'q12_9', question: 'Un administrateur tape "switchport mode dynamic desirable" sur un port. Quel est l\'effet ?', options: ['Le port reste en mode access quoi qu\'il arrive', 'Le port tente activement de negocier un trunk avec le port distant via DTP', 'Le port se configure en trunk statique sans negociation', 'Le port desactive DTP et reste dans son mode actuel'], correct: 1, explanation: 'En mode "dynamic desirable", le port initie activement la negociation DTP pour former un trunk. Il deviendra trunk si l\'autre cote est en mode trunk, dynamic desirable ou dynamic auto. Seul le mode access statique de l\'autre cote empechera le trunk.' },
    { id: 'q12_10', question: 'Quelle est la difference entre les VLANs de plage normale (1-1005) et de plage etendue (1006-4094) ?', options: ['Les VLANs etendus ne peuvent pas traverser de liens trunk', 'Les VLANs de plage normale sont stockes dans vlan.dat et supportes par VTP v1/v2, les VLANs etendus necessitent VTP v3 ou le mode transparent', 'Les VLANs etendus offrent un debit plus eleve que les VLANs normaux', 'Il n\'y a aucune difference fonctionnelle entre les deux plages'], correct: 1, explanation: 'Les VLANs 1-1005 sont stockes dans le fichier vlan.dat et supportes par VTP v1/v2. Les VLANs 1006-4094 necessitent VTP version 3 ou le mode VTP transparent pour etre configures. Ils ne sont pas propages par VTP v1/v2.' },
  ],
  13: [
    { id: 'q13_1', question: 'Quel est le role principal du protocole Spanning Tree (STP) ?', options: ['Router le trafic entre les VLANs', 'Empecher les boucles de couche 2 dans les reseaux commutes redondants', 'Distribuer la configuration des VLANs entre les switches', 'Negocier automatiquement la vitesse des liens entre switches'], correct: 1, explanation: 'STP (IEEE 802.1D) previent les boucles de couche 2 en bloquant certains ports redondants. Sans STP, les trames de broadcast circuleraient indefiniment entre les switches, provoquant une broadcast storm et la saturation du reseau.' },
    { id: 'q13_2', question: 'Comment le Root Bridge est-il elu dans STP ?', options: ['Le switch avec l\'adresse IP la plus basse est elu Root Bridge', 'Le switch avec le Bridge ID (priorite + adresse MAC) le plus bas est elu Root Bridge', 'Le premier switch a demarrer sur le reseau devient Root Bridge', 'Le switch ayant le plus de ports actifs est elu Root Bridge'], correct: 1, explanation: 'Le Root Bridge est elu en comparant les Bridge ID. Le Bridge ID est compose de la priorite (defaut 32768) et de l\'adresse MAC. Le switch avec le BID le plus bas gagne. On peut forcer l\'election en abaissant la priorite avec "spanning-tree vlan X priority".' },
    { id: 'q13_3', question: 'Quels sont les etats de port dans STP classique (802.1D) ?', options: ['Active, Standby, Down', 'Listening, Learning, Forwarding, Blocking, Disabled', 'Open, Closed, Half-Open', 'Root, Designated, Alternate, Backup'], correct: 1, explanation: 'STP 802.1D definit 5 etats de port : Blocking (bloque le trafic), Listening (ecoute les BPDU), Learning (apprend les MAC), Forwarding (transmet le trafic) et Disabled (administrativement desactive). La convergence prend environ 50 secondes.' },
    { id: 'q13_4', question: 'Quel est l\'avantage principal de RSTP (802.1w) par rapport a STP classique (802.1D) ?', options: ['RSTP supporte plus de VLANs que STP', 'RSTP converge beaucoup plus rapidement, en quelques secondes au lieu de 30-50 secondes', 'RSTP consomme moins de bande passante que STP', 'RSTP elimine completement le besoin de ports bloques'], correct: 1, explanation: 'RSTP (Rapid Spanning Tree Protocol, 802.1w) offre une convergence en 1 a 5 secondes grace a des mecanismes de synchronisation et de proposition/accord entre switches. STP classique prend 30 a 50 secondes a cause des timers Forward Delay (15s x2) et Max Age (20s).' },
    { id: 'q13_5', question: 'A quoi sert la fonctionnalite PortFast sur un port de switch ?', options: ['Elle accelere la negociation DTP sur les ports trunk', 'Elle permet a un port access de passer directement en etat Forwarding sans passer par Listening et Learning', 'Elle augmente la priorite du port pour qu\'il devienne Root Port', 'Elle desactive STP completement sur le port'], correct: 1, explanation: 'PortFast fait passer un port directement en etat Forwarding au lieu d\'attendre 30 secondes de convergence STP. Elle ne doit etre activee que sur les ports connectes a des hotes finaux (PC, serveurs), jamais sur des ports relies a d\'autres switches.' },
    { id: 'q13_6', question: 'Que fait BPDU Guard lorsqu\'il recoit un BPDU sur un port ou il est active ?', options: ['Il ignore le BPDU et continue a fonctionner normalement', 'Il met le port en etat err-disabled immediatement', 'Il recalcule la topologie STP pour integrer le nouveau switch', 'Il envoie un BPDU de reponse pour negocier avec le nouveau switch'], correct: 1, explanation: 'BPDU Guard protege le reseau en desactivant immediatement (err-disabled) un port PortFast qui recoit un BPDU. Cela empeche un switch non autorise de modifier la topologie STP. On le reactive avec "shutdown" puis "no shutdown" ou via errdisable recovery.' },
    { id: 'q13_7', question: 'Dans RSTP, quels sont les trois roles de ports possibles ?', options: ['Access, Trunk, EtherChannel', 'Root Port, Designated Port, Alternate/Backup Port', 'Forwarding Port, Blocking Port, Disabled Port', 'Upstream Port, Downstream Port, Peer Port'], correct: 1, explanation: 'RSTP definit les roles suivants : Root Port (meilleur chemin vers le Root Bridge), Designated Port (port qui transmet le trafic sur un segment), Alternate Port (chemin alternatif vers le Root Bridge, remplace le Blocking de STP) et Backup Port (redondance sur un meme segment).' },
    { id: 'q13_8', question: 'Quel est l\'avantage de Rapid PVST+ par rapport a RSTP standard ?', options: ['Rapid PVST+ est un standard ouvert utilise par tous les constructeurs', 'Rapid PVST+ cree une instance STP separee par VLAN, permettant un equilibrage de charge par VLAN', 'Rapid PVST+ utilise moins de ressources CPU que RSTP', 'Rapid PVST+ ne necessite pas d\'election de Root Bridge'], correct: 1, explanation: 'Rapid PVST+ (Per-VLAN Spanning Tree Plus) est la version Cisco de RSTP qui cree une instance STP independante par VLAN. Cela permet d\'avoir un Root Bridge different par VLAN et d\'equilibrer le trafic sur les liens redondants. L\'inconvenient est une consommation CPU plus elevee.' },
    { id: 'q13_9', question: 'Quelle commande Cisco configure un switch pour devenir Root Bridge pour le VLAN 10 ?', options: ['spanning-tree vlan 10 root primary', 'spanning-tree vlan 10 priority 0', 'stp vlan 10 root-bridge enable', 'spanning-tree mode root vlan 10'], correct: 0, explanation: 'La commande "spanning-tree vlan 10 root primary" configure la priorite du switch a 24576 (ou 4096 de moins que le Root Bridge actuel) pour le VLAN 10, le rendant Root Bridge. On peut aussi utiliser "spanning-tree vlan 10 priority 0" pour forcer la priorite la plus basse possible.' },
    { id: 'q13_10', question: 'Quel est le cout STP par defaut d\'un lien 1 Gbps dans RSTP ?', options: ['4', '19', '100', '200'], correct: 0, explanation: 'En RSTP (802.1w), le cout par defaut d\'un lien 1 Gbps est 4. Pour comparaison : 10 Gbps = 2, 100 Mbps = 19, 10 Mbps = 100. Ces couts sont definis par la norme IEEE 802.1D-2004 et sont utilises pour calculer le meilleur chemin vers le Root Bridge.' },
  ],
  14: [
    { id: 'q14_1', question: 'Pourquoi le routage inter-VLAN est-il necessaire ?', options: ['Pour permettre aux hotes d\'un meme VLAN de communiquer entre eux', 'Pour permettre la communication entre des hotes situes dans des VLANs differents, car un switch Layer 2 ne route pas entre VLANs', 'Pour accelerer le transfert de donnees au sein d\'un VLAN', 'Pour remplacer le protocole STP dans les reseaux commutes'], correct: 1, explanation: 'Chaque VLAN est un domaine de broadcast isole. Un switch Layer 2 ne peut pas router le trafic entre VLANs differents. Un equipement de couche 3 (routeur ou switch Layer 3) est necessaire pour permettre la communication inter-VLAN.' },
    { id: 'q14_2', question: 'Qu\'est-ce que la methode "Router-on-a-Stick" pour le routage inter-VLAN ?', options: ['Un routeur avec une interface physique par VLAN connectee a des ports access du switch', 'Un routeur avec une seule interface physique divisee en sous-interfaces, chacune associee a un VLAN via un lien trunk', 'Un switch Layer 2 configure avec des ACLs pour router entre VLANs', 'Deux routeurs connectes par un lien point-a-point pour router entre VLANs'], correct: 1, explanation: 'Router-on-a-Stick utilise une seule interface physique du routeur connectee en trunk a un switch. Des sous-interfaces (ex: G0/0.10, G0/0.20) sont creees sur le routeur, chacune encapsulant un VLAN specifique avec 802.1Q. Cette methode est economique mais peut creer un goulot d\'etranglement.' },
    { id: 'q14_3', question: 'Quelle commande configure l\'encapsulation 802.1Q sur une sous-interface de routeur pour le VLAN 20 ?', options: ['ip address 192.168.20.1 255.255.255.0 vlan 20', 'encapsulation dot1q 20', 'switchport trunk encapsulation dot1q', 'vlan encapsulation 20 dot1q'], correct: 1, explanation: 'Sur une sous-interface (ex: interface G0/0.20), la commande "encapsulation dot1q 20" associe cette sous-interface au VLAN 20. Chaque sous-interface recoit ensuite une adresse IP qui servira de passerelle par defaut pour les hotes du VLAN correspondant.' },
    { id: 'q14_4', question: 'Quel est l\'avantage principal d\'utiliser un switch Layer 3 pour le routage inter-VLAN ?', options: ['Il est moins cher qu\'un routeur classique', 'Il route en hardware (ASIC) a la vitesse du wire-speed, evitant le goulot d\'etranglement du Router-on-a-Stick', 'Il ne necessite aucune configuration supplementaire', 'Il supporte plus de VLANs qu\'un routeur'], correct: 1, explanation: 'Un switch Layer 3 effectue le routage inter-VLAN en hardware via des ASIC (circuits dedies), offrant un debit proche du wire-speed. Avec Router-on-a-Stick, tout le trafic inter-VLAN passe par un seul lien trunk, ce qui peut creer un goulot d\'etranglement sur les reseaux charges.' },
    { id: 'q14_5', question: 'Qu\'est-ce qu\'une SVI (Switched Virtual Interface) ?', options: ['Une interface physique sur un switch utilisee pour le trunking', 'Une interface virtuelle de couche 3 associee a un VLAN sur un switch Layer 3, servant de passerelle par defaut', 'Un port virtuel cree par STP pour la redondance', 'Un tunnel VPN configure sur un switch'], correct: 1, explanation: 'Une SVI est une interface logique de couche 3 creee sur un switch (commande "interface vlan X"). Elle recoit une adresse IP et sert de passerelle par defaut pour tous les hotes du VLAN. Sur un switch Layer 3 avec "ip routing" active, les SVIs permettent le routage inter-VLAN.' },
    { id: 'q14_6', question: 'Quelle commande active le routage IP sur un switch Layer 3 Cisco ?', options: ['router enable', 'ip routing', 'routing-mode layer3', 'switchport routing enable'], correct: 1, explanation: 'La commande "ip routing" en mode configuration globale active la fonction de routage sur un switch Layer 3. Sans cette commande, le switch ne peut pas router le trafic entre les VLANs meme si des SVIs sont configurees avec des adresses IP.' },
    { id: 'q14_7', question: 'Dans une configuration Router-on-a-Stick, que doit configurer l\'administrateur sur le switch ?', options: ['Une route statique vers chaque VLAN', 'Un port trunk vers le routeur avec les VLANs autorises', 'Une SVI pour chaque VLAN', 'Le protocole OSPF entre le switch et le routeur'], correct: 1, explanation: 'Le switch doit avoir un port configure en mode trunk (switchport mode trunk) vers le routeur, avec les VLANs concernes autorises. Le routeur gere le routage via ses sous-interfaces. Les ports des hotes sont configures en mode access dans leurs VLANs respectifs.' },
    { id: 'q14_8', question: 'Un hote du VLAN 10 (192.168.10.5) ne peut pas joindre un hote du VLAN 20 (192.168.20.10). La passerelle du VLAN 10 est 192.168.10.1. Quelle est la premiere verification a effectuer ?', options: ['Verifier que STP n\'a pas bloque le port de l\'hote', 'Verifier que l\'hote du VLAN 10 peut joindre sa passerelle 192.168.10.1 avec un ping', 'Verifier que les deux hotes utilisent le meme serveur DNS', 'Verifier que le VLAN 20 utilise le meme masque de sous-reseau que le VLAN 10'], correct: 1, explanation: 'La premiere etape de depannage est de verifier la connectivite entre l\'hote et sa passerelle par defaut (ping 192.168.10.1). Si ce ping echoue, le probleme est local (VLAN, port, cablage). Si ce ping reussit, le probleme se situe au niveau du routage inter-VLAN.' },
    { id: 'q14_9', question: 'Quelle est la methode de routage inter-VLAN la plus ancienne et la moins efficace ?', options: ['Router-on-a-Stick avec sous-interfaces', 'Le routage via des interfaces physiques separees, une par VLAN', 'Le routage par SVI sur switch Layer 3', 'Le routage par tunnels GRE entre VLANs'], correct: 1, explanation: 'La methode legacy utilise une interface physique du routeur par VLAN, chacune connectee a un port access du switch. C\'est inefficace car elle consomme une interface physique par VLAN et un port switch par connexion. Cette methode n\'est plus utilisee dans les reseaux modernes.' },
    { id: 'q14_10', question: 'Sur un switch Layer 3, quelle commande transforme un port physique en interface routee (Layer 3) ?', options: ['switchport mode routed', 'no switchport', 'ip routing interface', 'interface mode layer3'], correct: 1, explanation: 'La commande "no switchport" sur une interface physique d\'un switch Layer 3 la transforme en interface routee de couche 3. On peut ensuite lui assigner une adresse IP directement. Cette interface se comporte alors comme un port de routeur classique, sans appartenir a un VLAN.' },
  ],
  15: [
    { id: 'q15_1', question: 'Quel est le role principal de CDP (Cisco Discovery Protocol) ?', options: ['Router le trafic entre les reseaux', 'Decouvrir les equipements Cisco directement connectes et collecter des informations sur eux', 'Distribuer les configurations VLAN entre les switches', 'Chiffrer les communications entre equipements Cisco'], correct: 1, explanation: 'CDP est un protocole proprietaire Cisco de couche 2 qui permet de decouvrir les equipements Cisco voisins directement connectes. Il collecte des informations comme le nom d\'hote, le modele, les interfaces connectees, les adresses IP et la version d\'IOS.' },
    { id: 'q15_2', question: 'Quelle est la difference fondamentale entre CDP et LLDP ?', options: ['CDP fonctionne sur IP tandis que LLDP fonctionne sur Ethernet', 'CDP est proprietaire Cisco tandis que LLDP est un standard ouvert IEEE 802.1AB', 'CDP decouvre tous les equipements du reseau tandis que LLDP ne voit que les voisins directs', 'CDP est plus recent et performant que LLDP'], correct: 1, explanation: 'CDP est un protocole proprietaire Cisco. LLDP (Link Layer Discovery Protocol) est le standard ouvert IEEE 802.1AB qui offre des fonctionnalites similaires et fonctionne avec des equipements de differents constructeurs. Les deux operent en couche 2 et ne decouvrent que les voisins directs.' },
    { id: 'q15_3', question: 'Quelle commande affiche les informations detaillees sur les voisins CDP ?', options: ['show cdp', 'show cdp neighbors detail', 'show cdp interfaces', 'show cdp traffic'], correct: 1, explanation: 'La commande "show cdp neighbors detail" affiche des informations completes sur chaque voisin : nom d\'hote, adresse IP de gestion, plateforme/modele, version d\'IOS, interface locale et distante, et capacites (routeur, switch, etc.). "show cdp neighbors" donne un resume sans les adresses IP.' },
    { id: 'q15_4', question: 'A quelle frequence CDP envoie-t-il des annonces par defaut ?', options: ['Toutes les 30 secondes', 'Toutes les 60 secondes', 'Toutes les 90 secondes', 'Toutes les 120 secondes'], correct: 1, explanation: 'Par defaut, CDP envoie des annonces toutes les 60 secondes. Le holdtime (temps de retention avant suppression d\'un voisin inactif) est de 180 secondes (3 fois le timer). Ces valeurs sont modifiables avec "cdp timer" et "cdp holdtime".' },
    { id: 'q15_5', question: 'Pourquoi est-il recommande de desactiver CDP sur les interfaces connectees a des reseaux externes non securises ?', options: ['CDP consomme trop de bande passante sur les liens WAN', 'CDP divulgue des informations sensibles (modele, version IOS, adresses IP) qui pourraient etre exploitees par un attaquant', 'CDP interfere avec le fonctionnement des protocoles de routage', 'CDP n\'est pas compatible avec les equipements non-Cisco sur les liens externes'], correct: 1, explanation: 'CDP revele des informations comme le modele d\'equipement, la version d\'IOS, les adresses IP et les VLANs. Un attaquant sur un lien non securise pourrait exploiter ces informations pour identifier des vulnerabilites. On le desactive par interface avec "no cdp enable" ou globalement avec "no cdp run".' },
    { id: 'q15_6', question: 'Quelle commande active LLDP globalement sur un equipement Cisco ?', options: ['lldp enable', 'lldp run', 'enable lldp global', 'set lldp active'], correct: 1, explanation: 'La commande "lldp run" en mode configuration globale active LLDP sur l\'equipement. Contrairement a CDP qui est active par defaut sur les equipements Cisco, LLDP doit etre active manuellement. On peut ensuite le desactiver par interface avec "no lldp transmit" et "no lldp receive".' },
    { id: 'q15_7', question: 'Quelles informations LLDP peut-il collecter sur un voisin ?', options: ['Uniquement le nom d\'hote et l\'adresse MAC', 'Le nom d\'hote, l\'adresse IP de gestion, les capacites systeme, l\'interface connectee et la description du port', 'Uniquement l\'adresse IP et le modele de l\'equipement', 'Le mot de passe et la configuration complete du voisin'], correct: 1, explanation: 'LLDP utilise des TLV (Type-Length-Value) pour transporter diverses informations : System Name, System Description, Port Description, Management Address, System Capabilities (routeur, switch, telephone), et d\'autres TLV optionnels comme LLDP-MED pour la VoIP.' },
    { id: 'q15_8', question: 'Quelle commande affiche les voisins decouverts par LLDP sur un switch Cisco ?', options: ['show lldp traffic', 'show lldp neighbors', 'show lldp interfaces', 'show lldp status'], correct: 1, explanation: 'La commande "show lldp neighbors" affiche la liste des equipements voisins decouverts par LLDP avec leur identifiant, l\'interface locale et distante, et le holdtime. "show lldp neighbors detail" ajoute les adresses IP de gestion et les capacites systeme.' },
    { id: 'q15_9', question: 'Dans quel cas LLDP-MED (Media Endpoint Discovery) est-il particulierement utile ?', options: ['Pour le routage inter-VLAN', 'Pour la decouverte et la configuration automatique de telephones IP et d\'equipements VoIP', 'Pour le chiffrement des communications CDP', 'Pour la detection de boucles STP'], correct: 1, explanation: 'LLDP-MED est une extension de LLDP concue pour les environnements VoIP. Elle permet aux telephones IP de decouvrir automatiquement le VLAN voix, la politique QoS, la localisation pour les appels d\'urgence (E911) et les parametres d\'alimentation PoE.' },
    { id: 'q15_10', question: 'Quelle commande desactive CDP sur une interface specifique sans affecter les autres interfaces ?', options: ['no cdp run', 'no cdp enable', 'cdp disable interface', 'shutdown cdp'], correct: 1, explanation: 'La commande "no cdp enable" en mode configuration d\'interface desactive CDP uniquement sur cette interface. La commande "no cdp run" (mode global) desactive CDP sur toutes les interfaces de l\'equipement. Il est courant de desactiver CDP par interface sur les ports connectes a des reseaux non securises.' },
  ],
  16: [
    { id: 'q16_1', question: 'Quel est le principal avantage d\'un EtherChannel ?', options: ['Il chiffre le trafic entre deux switches', 'Il regroupe plusieurs liens physiques en un seul lien logique, augmentant la bande passante et la redondance', 'Il remplace le protocole STP sur les liens redondants', 'Il permet le routage inter-VLAN sans equipement de couche 3'], correct: 1, explanation: 'EtherChannel (ou Port-Channel) combine 2 a 8 liens physiques en un seul lien logique. Cela multiplie la bande passante disponible et offre de la redondance : si un lien tombe, les autres continuent de fonctionner. STP voit le groupe comme un seul lien et ne bloque pas les liens individuels.' },
    { id: 'q16_2', question: 'Quelle est la difference entre LACP et PAgP ?', options: ['LACP est plus rapide que PAgP', 'LACP est un standard ouvert IEEE 802.3ad tandis que PAgP est un protocole proprietaire Cisco', 'PAgP est un standard IEEE et LACP est proprietaire Cisco', 'LACP supporte jusqu\'a 16 liens tandis que PAgP est limite a 4'], correct: 1, explanation: 'LACP (Link Aggregation Control Protocol) est defini par le standard IEEE 802.3ad (maintenant 802.1AX) et fonctionne avec tout constructeur. PAgP (Port Aggregation Protocol) est proprietaire Cisco. LACP est recommande pour l\'interoperabilite multi-constructeurs.' },
    { id: 'q16_3', question: 'Quels sont les deux modes LACP qui permettent la negociation d\'un EtherChannel ?', options: ['On et Off', 'Active et Passive', 'Desirable et Auto', 'Enable et Disable'], correct: 1, explanation: 'LACP utilise les modes Active (initie la negociation) et Passive (repond a la negociation). Un EtherChannel se forme si au moins un cote est en Active. Deux cotes en Passive ne formeront jamais d\'EtherChannel. Les modes Desirable/Auto sont pour PAgP.' },
    { id: 'q16_4', question: 'Quelle condition doit etre respectee pour que les ports forment un EtherChannel ?', options: ['Les ports doivent etre sur des switches de modeles differents', 'Tous les ports du groupe doivent avoir la meme vitesse, le meme duplex, le meme VLAN et les memes parametres trunk', 'Les ports doivent obligatoirement etre contigus (ports 1-2-3-4)', 'Chaque port doit etre dans un VLAN different pour l\'equilibrage'], correct: 1, explanation: 'Pour former un EtherChannel, tous les ports doivent avoir des parametres identiques : vitesse, duplex, mode (access/trunk), VLAN(s) autorises, VLAN natif et STP cost. Toute incoherence empeche la formation du bundle ou provoque une erreur.' },
    { id: 'q16_5', question: 'Quelle commande cree un EtherChannel LACP en mode actif sur les interfaces Gi0/1 et Gi0/2 ?', options: ['channel-group 1 mode on', 'channel-group 1 mode active', 'lacp channel-group 1', 'etherchannel 1 mode lacp active'], correct: 1, explanation: 'Sous les interfaces Gi0/1 et Gi0/2, la commande "channel-group 1 mode active" les ajoute au Port-Channel 1 en mode LACP actif. Le mode "active" initie activement la negociation LACP. L\'interface logique "Port-Channel 1" est creee automatiquement.' },
    { id: 'q16_6', question: 'Quel algorithme est utilise par defaut pour repartir le trafic sur les liens d\'un EtherChannel ?', options: ['Round-robin (chaque trame sur un lien different)', 'Hash base sur les adresses MAC source ou source-destination', 'Le lien avec le moins de trafic recoit la prochaine trame', 'Tout le trafic passe par le premier lien disponible'], correct: 1, explanation: 'EtherChannel utilise un algorithme de hash pour repartir le trafic. Par defaut, le hash est base sur les adresses MAC source, source-destination, ou IP (selon la plateforme). On peut le modifier avec "port-channel load-balance". Le round-robin n\'est pas utilise car il pourrait desorganiser l\'ordre des trames.' },
    { id: 'q16_7', question: 'Que signifie le mode "on" lors de la configuration d\'un EtherChannel ?', options: ['Le mode "on" active la negociation automatique via LACP', 'Le mode "on" force la creation du EtherChannel sans aucune negociation (ni LACP ni PAgP)', 'Le mode "on" est synonyme du mode "active" en LACP', 'Le mode "on" active le mode PAgP desirable'], correct: 1, explanation: 'Le mode "on" force la creation de l\'EtherChannel sans protocole de negociation. Les deux cotes doivent etre en mode "on". C\'est risque car il n\'y a pas de verification de compatibilite. Il est recommande d\'utiliser LACP active/passive pour une detection et une recuperation automatiques des erreurs.' },
    { id: 'q16_8', question: 'Combien de liens physiques LACP peut-il regrouper au maximum dans un EtherChannel actif ?', options: ['4 liens actifs', '8 liens actifs', '16 liens actifs', '2 liens actifs'], correct: 1, explanation: 'LACP supporte jusqu\'a 16 liens dans un groupe, mais seuls 8 peuvent etre actifs simultanement. Les 8 autres restent en mode standby (hot-standby) et prennent le relais automatiquement si un lien actif tombe. La selection des liens actifs est basee sur la priorite de port LACP.' },
    { id: 'q16_9', question: 'Quelle commande affiche l\'etat d\'un EtherChannel et de ses ports membres ?', options: ['show interfaces port-channel', 'show etherchannel summary', 'show lacp status', 'show channel-group detail'], correct: 1, explanation: '"show etherchannel summary" affiche un resume de tous les EtherChannels avec leur protocole (LACP/PAgP/none), l\'etat du Port-Channel (U=Up, D=Down) et l\'etat de chaque port membre (P=bundled, s=suspended, I=standalone). C\'est la commande la plus utilisee pour le diagnostic.' },
    { id: 'q16_10', question: 'Que se passe-t-il si un lien physique d\'un EtherChannel tombe en panne ?', options: ['Tout l\'EtherChannel tombe et le trafic est interrompu', 'Le trafic est redistribue automatiquement sur les liens restants sans interruption', 'STP doit reconverger avant que le trafic puisse etre redistribue', 'Le switch desactive tous les liens du bundle par securite'], correct: 1, explanation: 'Si un lien physique d\'un EtherChannel tombe, le trafic est automatiquement redistribue sur les liens restants sans interruption de service. La bande passante totale diminue mais la connectivite est maintenue. C\'est un des avantages majeurs de l\'EtherChannel pour la haute disponibilite.' },
  ],
  17: [
    { id: 'q17_1', question: 'Quels sont les principaux composants d\'une entree dans la table de routage ?', options: ['Adresse MAC destination, port de sortie et priorite', 'Reseau de destination, masque de sous-reseau, next-hop ou interface de sortie, distance administrative et metrique', 'Adresse IP source, adresse IP destination et TTL', 'Protocole, numero de port et adresse de broadcast'], correct: 1, explanation: 'Chaque entree de la table de routage contient : le reseau de destination avec son masque (prefixe), le next-hop (IP du prochain routeur) ou l\'interface de sortie, la distance administrative (fiabilite de la source), la metrique (cout du chemin) et la source de la route (C, S, O, R, etc.).' },
    { id: 'q17_2', question: 'Qu\'est-ce que la distance administrative (AD) dans une table de routage ?', options: ['La distance physique en metres entre deux routeurs', 'Une valeur qui represente la fiabilite de la source d\'une route — plus elle est basse, plus la route est preferee', 'Le nombre de sauts pour atteindre la destination', 'La bande passante disponible sur le chemin'], correct: 1, explanation: 'La distance administrative (AD) est une valeur de 0 a 255 attribuee a chaque source de route. Elle permet au routeur de choisir entre des routes vers la meme destination apprises par differentes sources. Les valeurs par defaut : Connected=0, Static=1, EIGRP=90, OSPF=110, RIP=120.' },
    { id: 'q17_3', question: 'Qu\'est-ce que le principe du "Longest Prefix Match" lors de la recherche dans la table de routage ?', options: ['Le routeur choisit la route avec le prefixe le plus court (masque le plus petit)', 'Le routeur choisit la route avec le prefixe le plus long (masque le plus specifique) correspondant a l\'adresse IP de destination', 'Le routeur choisit la route la plus ancienne dans la table', 'Le routeur choisit la route avec la metrique la plus elevee'], correct: 1, explanation: 'Le Longest Prefix Match signifie que lorsqu\'un paquet correspond a plusieurs routes, le routeur choisit celle avec le masque le plus long (le plus specifique). Par exemple, pour 192.168.1.50, une route /28 sera preferee a une route /24 car elle est plus precise.' },
    { id: 'q17_4', question: 'Quelle commande affiche la table de routage sur un routeur Cisco ?', options: ['show routing-table', 'show ip route', 'display ip routes', 'show route all'], correct: 1, explanation: '"show ip route" affiche la table de routage complete avec toutes les routes connues. On peut filtrer par protocole (show ip route ospf), par reseau (show ip route 192.168.1.0) ou par type (show ip route connected, show ip route static). Pour IPv6, on utilise "show ipv6 route".' },
    { id: 'q17_5', question: 'Que signifie le code "C" dans la table de routage Cisco ?', options: ['Route apprise par CDP', 'Route directement connectee (Connected) a une interface du routeur', 'Route apprise par un protocole de routage classful', 'Route mise en cache dans la table de routage'], correct: 1, explanation: 'Le code "C" signifie Connected : c\'est un reseau directement connecte a une interface active du routeur. Ces routes ont une AD de 0 (la plus fiable). Le code "L" (Local) indique l\'adresse IP specifique de l\'interface avec un masque /32.' },
    { id: 'q17_6', question: 'Quelle est la metrique utilisee par OSPF pour calculer le meilleur chemin ?', options: ['Le nombre de sauts (hop count)', 'Le cout base sur la bande passante de reference divisee par la bande passante de l\'interface', 'Le delai de propagation en millisecondes', 'La charge CPU du routeur next-hop'], correct: 1, explanation: 'OSPF utilise le cout (cost) comme metrique, calcule par la formule : Reference Bandwidth / Interface Bandwidth. Par defaut, la reference est 100 Mbps. Ainsi un lien 100 Mbps = cout 1, un lien 10 Mbps = cout 10. On peut modifier la reference avec "auto-cost reference-bandwidth".' },
    { id: 'q17_7', question: 'Que signifie "Gateway of Last Resort is not set" dans la sortie de show ip route ?', options: ['Le routeur n\'a pas de route par defaut (0.0.0.0/0) configuree', 'Le routeur ne peut joindre aucun reseau', 'La passerelle par defaut a ete desactivee manuellement', 'Le routeur est en mode de maintenance'], correct: 0, explanation: '"Gateway of Last Resort is not set" indique qu\'aucune route par defaut (0.0.0.0/0) n\'est configuree. Si un paquet ne correspond a aucune route specifique dans la table, il sera rejete. Pour definir une route par defaut : "ip route 0.0.0.0 0.0.0.0 [next-hop]".' },
    { id: 'q17_8', question: 'Quelle est la distance administrative d\'une route apprise par EIGRP interne ?', options: ['20', '90', '110', '170'], correct: 1, explanation: 'EIGRP interne a une AD de 90. Les principales AD par defaut sont : Connected=0, Static=1, eBGP=20, EIGRP interne=90, OSPF=110, IS-IS=115, RIP=120, EIGRP externe=170, iBGP=200. Une route avec une AD de 255 est consideree comme non fiable et ne sera pas installee.' },
    { id: 'q17_9', question: 'Un routeur a deux routes vers 10.0.0.0/24 : une via OSPF (AD=110, cost=50) et une via RIP (AD=120, hop=3). Laquelle sera installee ?', options: ['La route RIP car elle a moins de sauts', 'La route OSPF car elle a la distance administrative la plus basse', 'Les deux routes seront installees pour l\'equilibrage de charge', 'Aucune des deux, le routeur attend une confirmation'], correct: 1, explanation: 'Quand des routes vers la meme destination sont apprises par differents protocoles, la distance administrative (AD) decide. OSPF (AD=110) est prefere a RIP (AD=120). La metrique n\'est comparee qu\'entre routes du meme protocole. La route OSPF sera installee dans la table de routage.' },
    { id: 'q17_10', question: 'Que represente le symbole "*" dans la ligne "Gateway of Last Resort is 10.0.0.1 to network 0.0.0.0" ?', options: ['Une route en erreur necessitant une intervention', 'La route par defaut candidate (default route) qui sera utilisee pour tout trafic sans correspondance plus specifique', 'Une route temporaire qui expirera bientot', 'Une route multicast speciale'], correct: 1, explanation: 'L\'asterisque (*) dans "S* 0.0.0.0/0" indique que cette route est la route par defaut candidate (candidate default route). Elle sera utilisee pour acheminer tout paquet dont la destination ne correspond a aucune route plus specifique dans la table de routage.' },
  ],
  18: [
    { id: 'q18_1', question: 'Quelle commande configure une route statique vers le reseau 192.168.10.0/24 via le next-hop 10.0.0.2 ?', options: ['route add 192.168.10.0/24 via 10.0.0.2', 'ip route 192.168.10.0 255.255.255.0 10.0.0.2', 'static-route 192.168.10.0 255.255.255.0 next-hop 10.0.0.2', 'set ip route 192.168.10.0/24 gateway 10.0.0.2'], correct: 1, explanation: 'La syntaxe Cisco pour une route statique est "ip route [reseau] [masque] [next-hop ou interface]". Ici, "ip route 192.168.10.0 255.255.255.0 10.0.0.2" indique que pour joindre 192.168.10.0/24, les paquets doivent etre envoyes a 10.0.0.2.' },
    { id: 'q18_2', question: 'Quelle est la commande pour configurer une route par defaut (default route) via 203.0.113.1 ?', options: ['ip route default 203.0.113.1', 'ip route 0.0.0.0 0.0.0.0 203.0.113.1', 'ip default-route 203.0.113.1', 'ip route any any 203.0.113.1'], correct: 1, explanation: 'La route par defaut utilise le reseau 0.0.0.0 avec le masque 0.0.0.0, ce qui correspond a toutes les destinations. "ip route 0.0.0.0 0.0.0.0 203.0.113.1" envoie tout trafic sans route plus specifique vers 203.0.113.1. C\'est typiquement la route vers le routeur du FAI.' },
    { id: 'q18_3', question: 'Qu\'est-ce qu\'une route statique flottante (floating static route) ?', options: ['Une route statique qui change de next-hop automatiquement', 'Une route statique configuree avec une AD plus elevee que la route principale, servant de route de secours', 'Une route statique qui n\'est active que pendant certaines heures', 'Une route statique distribuee par un protocole de routage dynamique'], correct: 1, explanation: 'Une floating static route est une route statique avec une AD manuellement elevee (ex: 200) pour qu\'elle ne soit utilisee que si la route principale (apprise par OSPF AD=110, par exemple) disparait. Exemple : "ip route 10.0.0.0 255.0.0.0 192.168.1.1 200". Elle sert de backup.' },
    { id: 'q18_4', question: 'Quelle est la difference entre une route statique avec next-hop et une route statique avec interface de sortie ?', options: ['Il n\'y a aucune difference, les deux fonctionnent de maniere identique', 'Avec next-hop, le routeur effectue une recherche recursive pour trouver l\'interface; avec interface de sortie, il envoie directement via cette interface', 'La route avec interface de sortie est toujours plus rapide', 'La route avec next-hop ne fonctionne qu\'avec OSPF'], correct: 1, explanation: 'Avec un next-hop IP, le routeur fait une lookup recursive pour determiner par quelle interface joindre ce next-hop. Avec une interface de sortie (ex: G0/0), le routeur envoie les paquets directement via cette interface. Sur les liens point-a-point, l\'interface de sortie suffit. Sur les reseaux multi-acces, le next-hop est prefere pour eviter les problemes ARP.' },
    { id: 'q18_5', question: 'Pourquoi les routes statiques ne sont-elles pas adaptees aux grands reseaux ?', options: ['Elles consomment trop de bande passante', 'Elles ne s\'adaptent pas automatiquement aux changements de topologie et necessitent une mise a jour manuelle sur chaque routeur', 'Elles sont moins securisees que les routes dynamiques', 'Elles ne supportent pas IPv6'], correct: 1, explanation: 'Les routes statiques doivent etre configurees et maintenues manuellement sur chaque routeur. Dans un grand reseau, chaque changement de topologie (panne de lien, ajout de reseau) necessite une intervention humaine. Les protocoles de routage dynamique s\'adaptent automatiquement a ces changements.' },
    { id: 'q18_6', question: 'Quelle commande configure une route statique IPv6 vers 2001:db8:acad::/48 via le next-hop fe80::1 sur l\'interface G0/0 ?', options: ['ipv6 route 2001:db8:acad::/48 fe80::1', 'ipv6 route 2001:db8:acad::/48 G0/0 fe80::1', 'ip route ipv6 2001:db8:acad::/48 fe80::1 G0/0', 'route ipv6 2001:db8:acad::/48 next-hop fe80::1'], correct: 1, explanation: 'Pour les routes statiques IPv6 avec un next-hop link-local (fe80::), il faut specifier l\'interface de sortie car l\'adresse link-local n\'est pas unique sur le routeur (elle peut exister sur plusieurs interfaces). La syntaxe est "ipv6 route [prefixe] [interface] [next-hop-link-local]".' },
    { id: 'q18_7', question: 'Quelle est la distance administrative par defaut d\'une route statique sur un routeur Cisco ?', options: ['0', '1', '5', '20'], correct: 1, explanation: 'Une route statique a une AD de 1 par defaut, ce qui la rend preferee a toutes les routes apprises par des protocoles de routage dynamique (EIGRP=90, OSPF=110, RIP=120). Seules les routes directement connectees (AD=0) sont preferees. On peut modifier l\'AD d\'une route statique en ajoutant la valeur a la fin de la commande.' },
    { id: 'q18_8', question: 'Qu\'est-ce qu\'une route statique recapitulative (summary static route) ?', options: ['Une route qui affiche un resume de toutes les routes statiques configurees', 'Une route statique qui couvre plusieurs sous-reseaux en utilisant un masque plus court, reduisant le nombre d\'entrees dans la table', 'Une route statique qui recapitule les routes OSPF', 'Une route qui envoie un rapport au serveur de supervision'], correct: 1, explanation: 'Une route statique recapitulative utilise un masque plus court pour couvrir plusieurs sous-reseaux. Par exemple, au lieu de 4 routes vers 192.168.0.0/24, 192.168.1.0/24, 192.168.2.0/24 et 192.168.3.0/24, on configure une seule route vers 192.168.0.0/22, reduisant la table de routage.' },
    { id: 'q18_9', question: 'Que se passe-t-il si l\'interface de sortie d\'une route statique tombe ?', options: ['La route reste dans la table de routage indefiniment', 'La route est automatiquement retiree de la table de routage tant que l\'interface est down', 'Le routeur recalcule la route avec un protocole dynamique', 'Le routeur envoie une alerte SNMP mais garde la route'], correct: 1, explanation: 'Quand l\'interface de sortie d\'une route statique passe en etat down, la route est automatiquement retiree de la table de routage. Elle sera reinstallee lorsque l\'interface redevient active. C\'est le meme comportement pour les routes avec next-hop si le routeur detecte que le next-hop est injoignable.' },
    { id: 'q18_10', question: 'Dans quel scenario une route statique completement specifiee (fully specified) est-elle necessaire ?', options: ['Lorsque le reseau de destination est tres grand', 'Lorsque l\'interface de sortie est un reseau multi-acces (Ethernet) et qu\'il faut specifier a la fois l\'interface et le next-hop', 'Lorsque le routeur a une seule interface', 'Lorsqu\'on utilise un protocole de routage dynamique en parallele'], correct: 1, explanation: 'Sur un reseau multi-acces comme Ethernet, une route avec seulement l\'interface de sortie necessite une resolution ARP pour chaque destination, ce qui est inefficace. En specifiant a la fois l\'interface et le next-hop (fully specified), le routeur fait une seule resolution ARP vers le next-hop, ce qui est beaucoup plus efficace.' },
  ],
  19: [
    { id: 'q19_1', question: 'Quelle est la taille d\'une adresse IPv6 et comment est-elle representee ?', options: ['64 bits, en notation decimale pointee', '128 bits, en 8 groupes de 4 chiffres hexadecimaux separes par des deux-points', '48 bits, en notation hexadecimale avec des tirets', '256 bits, en 16 groupes de 4 chiffres hexadecimaux'], correct: 1, explanation: 'IPv6 utilise des adresses de 128 bits representees en 8 groupes de 4 chiffres hexadecimaux separes par des ":" (ex: 2001:0db8:0000:0000:0000:0000:0000:0001). On peut simplifier en supprimant les zeros en tete et en remplacant un ou plusieurs groupes consecutifs de zeros par "::" (une seule fois).' },
    { id: 'q19_2', question: 'Qu\'est-ce que SLAAC (Stateless Address Autoconfiguration) ?', options: ['Un protocole de routage IPv6', 'Un mecanisme permettant a un hote de configurer automatiquement son adresse IPv6 a partir du prefixe annonce par le routeur, sans serveur DHCP', 'Un outil de diagnostic pour tester la connectivite IPv6', 'Un protocole de securite pour chiffrer les adresses IPv6'], correct: 1, explanation: 'SLAAC permet a un hote de generer automatiquement son adresse IPv6 en combinant le prefixe reseau (recu via un Router Advertisement) avec un identifiant d\'interface (derive de l\'adresse MAC via EUI-64 ou genere aleatoirement). Aucun serveur DHCP n\'est necessaire pour l\'attribution d\'adresse.' },
    { id: 'q19_3', question: 'Quel protocole IPv6 remplace ARP utilise en IPv4 ?', options: ['ARPv6', 'NDP (Neighbor Discovery Protocol) avec les messages Neighbor Solicitation et Neighbor Advertisement', 'DHCPv6', 'ICMPv6 Echo Request'], correct: 1, explanation: 'NDP (Neighbor Discovery Protocol, ICMPv6) remplace ARP en IPv6. Il utilise des messages Neighbor Solicitation (NS) et Neighbor Advertisement (NA) pour resoudre les adresses IPv6 en adresses MAC. NDP utilise le multicast solicited-node au lieu du broadcast, ce qui est plus efficace.' },
    { id: 'q19_4', question: 'Quelle est la difference entre DHCPv6 stateless et DHCPv6 stateful ?', options: ['Le stateless est plus lent que le stateful', 'Le stateless fournit uniquement des informations complementaires (DNS, domaine) tandis que le stateful attribue les adresses IPv6 et maintient un etat', 'Le stateless fonctionne uniquement sur les liens locaux', 'Il n\'y a aucune difference, ce sont deux noms pour le meme protocole'], correct: 1, explanation: 'DHCPv6 stateless (flag O=1, M=0) fournit des informations comme le serveur DNS et le nom de domaine, mais l\'adresse IPv6 est obtenue via SLAAC. DHCPv6 stateful (flag M=1) attribue les adresses IPv6, les prefixes et d\'autres parametres, en maintenant un etat (table d\'attribution) comme DHCPv4.' },
    { id: 'q19_5', question: 'Quelle commande active IPv6 sur une interface et lui attribue une adresse ?', options: ['ip address 2001:db8::1/64', 'ipv6 address 2001:db8::1/64', 'set ipv6 2001:db8::1/64', 'interface ipv6 address 2001:db8::1/64'], correct: 1, explanation: 'La commande "ipv6 address [adresse]/[prefixe]" en mode configuration d\'interface attribue une adresse IPv6. Il faut aussi activer le routage IPv6 globalement avec "ipv6 unicast-routing". Une adresse link-local (fe80::) est automatiquement generee sur l\'interface activee.' },
    { id: 'q19_6', question: 'Quel type d\'adresse IPv6 est utilise uniquement pour la communication sur un meme segment de reseau local ?', options: ['Global Unicast Address (GUA)', 'Link-Local Address (fe80::/10)', 'Unique Local Address (ULA)', 'Multicast Address (ff00::/8)'], correct: 1, explanation: 'Les adresses Link-Local (fe80::/10) sont utilisees exclusivement pour la communication sur le meme lien (segment L2). Elles ne sont jamais routees au-dela du lien local. Chaque interface IPv6 genere automatiquement une adresse link-local. Elles sont utilisees par NDP, OSPFv3 et comme next-hop dans les routes.' },
    { id: 'q19_7', question: 'Qu\'est-ce que le processus EUI-64 utilise par SLAAC ?', options: ['Un algorithme de chiffrement pour securiser les adresses IPv6', 'Un processus qui genere l\'identifiant d\'interface 64 bits a partir de l\'adresse MAC 48 bits en inserant FF:FE au milieu et en inversant le bit U/L', 'Un protocole de negociation entre hote et routeur pour l\'attribution d\'adresse', 'Un mecanisme de compression des adresses IPv6'], correct: 1, explanation: 'EUI-64 convertit une adresse MAC 48 bits en identifiant d\'interface 64 bits : on insere FF:FE entre les 3 premiers et les 3 derniers octets de la MAC, puis on inverse le 7e bit (bit U/L). Exemple : MAC 00:1A:2B:3C:4D:5E donne 021A:2BFF:FE3C:4D5E. Pour des raisons de vie privee, les adresses aleatoires sont souvent preferees.' },
    { id: 'q19_8', question: 'Quel message ICMPv6 un routeur envoie-t-il periodiquement pour annoncer le prefixe reseau et les parametres ?', options: ['Neighbor Solicitation (NS)', 'Router Advertisement (RA)', 'Router Solicitation (RS)', 'Redirect Message'], correct: 1, explanation: 'Le Router Advertisement (RA, ICMPv6 type 134) est envoye periodiquement par les routeurs (toutes les 200 secondes par defaut) ou en reponse a un Router Solicitation. Il contient le prefixe reseau, les flags M et O (pour DHCPv6), la duree de validite du prefixe et les informations de passerelle par defaut.' },
    { id: 'q19_9', question: 'Quelle commande configure une interface pour obtenir son adresse IPv6 via SLAAC ?', options: ['ipv6 address dhcp', 'ipv6 address autoconfig', 'ipv6 address slaac enable', 'ipv6 auto-address'], correct: 1, explanation: 'La commande "ipv6 address autoconfig" sur une interface permet a l\'equipement d\'obtenir son adresse IPv6 automatiquement via SLAAC. L\'interface ecoutera les Router Advertisements pour obtenir le prefixe reseau et generera son identifiant d\'interface (EUI-64 ou aleatoire).' },
    { id: 'q19_10', question: 'Quel est le prefixe des adresses IPv6 Global Unicast (GUA) publiquement routables ?', options: ['fe80::/10', 'fc00::/7', '2000::/3', 'ff00::/8'], correct: 2, explanation: 'Les adresses Global Unicast (GUA) commencent par le prefixe 2000::/3 (2000:: a 3FFF::). Ce sont l\'equivalent des adresses IPv4 publiques, routables sur Internet. Les adresses Link-Local (fe80::/10) sont locales au lien, les ULA (fc00::/7) sont privees et les multicast (ff00::/8) sont pour le multicast.' },
  ],
  20: [
    { id: 'q20_1', question: 'Quel algorithme OSPF utilise-t-il pour calculer le plus court chemin vers chaque destination ?', options: ['Bellman-Ford', 'DUAL (Diffusing Update Algorithm)', 'Dijkstra (SPF - Shortest Path First)', 'Distance Vector'], correct: 2, explanation: 'OSPF utilise l\'algorithme de Dijkstra, aussi appele SPF (Shortest Path First), pour construire un arbre du plus court chemin (SPF Tree) avec le routeur local comme racine. Chaque routeur OSPF possede une copie identique de la base de donnees des etats de liens (LSDB) et calcule ses propres meilleurs chemins.' },
    { id: 'q20_2', question: 'Comment le Router ID OSPF est-il determine si aucun n\'est configure manuellement ?', options: ['L\'adresse MAC la plus basse du routeur est utilisee', 'La plus haute adresse IP de loopback active est choisie, sinon la plus haute adresse IP d\'une interface physique active', 'L\'adresse IP de l\'interface la plus rapide est utilisee', 'Un identifiant aleatoire est genere automatiquement'], correct: 1, explanation: 'Le Router ID OSPF est choisi dans cet ordre : 1) Configuration manuelle via "router-id X.X.X.X", 2) La plus haute adresse IP parmi les interfaces loopback actives, 3) La plus haute adresse IP parmi les interfaces physiques actives. Il est fortement recommande de configurer le Router ID manuellement pour la stabilite.' },
    { id: 'q20_3', question: 'Quel est le role du DR (Designated Router) dans un reseau multi-acces OSPF ?', options: ['Il est le root bridge pour STP', 'Il centralise les echanges de LSA sur un segment multi-acces pour reduire le nombre d\'adjacences OSPF', 'Il distribue les adresses IP via DHCP', 'Il route tout le trafic du segment vers les autres aires'], correct: 1, explanation: 'Sur un reseau multi-acces (Ethernet), sans DR, chaque routeur formerait une adjacence avec tous les autres (n*(n-1)/2). Le DR centralise les echanges de LSA : les routeurs envoient leurs mises a jour au DR (224.0.0.6) qui les redistribue a tous (224.0.0.5). Le BDR prend le relais si le DR tombe.' },
    { id: 'q20_4', question: 'Quelle commande active le processus OSPF et annonce les reseaux 192.168.1.0/24 et 10.0.0.0/8 ?', options: ['router ospf 1 / network 192.168.1.0 0.0.0.255 area 0 / network 10.0.0.0 0.255.255.255 area 0', 'ospf enable / add network 192.168.1.0/24 area 0 / add network 10.0.0.0/8 area 0', 'ip ospf 1 area 0 / advertise 192.168.1.0/24 / advertise 10.0.0.0/8', 'enable ospf process 1 / route 192.168.1.0 area 0 / route 10.0.0.0 area 0'], correct: 0, explanation: 'On active OSPF avec "router ospf [process-id]" puis on annonce les reseaux avec "network [reseau] [wildcard-mask] area [area-id]". Le wildcard mask est l\'inverse du masque de sous-reseau. Le process-id est local au routeur et n\'a pas besoin d\'etre identique entre voisins.' },
    { id: 'q20_5', question: 'Quels sont les intervalles Hello et Dead par defaut d\'OSPF sur un reseau broadcast ?', options: ['5 secondes / 20 secondes', '10 secondes / 40 secondes', '30 secondes / 90 secondes', '60 secondes / 180 secondes'], correct: 1, explanation: 'Sur un reseau broadcast, OSPF envoie des paquets Hello toutes les 10 secondes. Le Dead interval est par defaut 4 fois le Hello interval, soit 40 secondes. Si aucun Hello n\'est recu dans ce delai, le voisin est declare down. Sur les reseaux NBMA, les intervalles sont 30/120 secondes.' },
    { id: 'q20_6', question: 'Quelle commande modifie le cout OSPF d\'une interface ?', options: ['ospf metric 50', 'ip ospf cost 50', 'set ospf cost 50', 'bandwidth cost 50'], correct: 1, explanation: 'La commande "ip ospf cost [valeur]" en mode configuration d\'interface modifie directement le cout OSPF. On peut aussi modifier la bande passante de reference globale avec "auto-cost reference-bandwidth [valeur-en-Mbps]" sous le processus OSPF. Pour les liens Gigabit et 10G, il est recommande d\'augmenter la reference-bandwidth.' },
    { id: 'q20_7', question: 'Comment le DR est-il elu sur un segment multi-acces OSPF ?', options: ['Le routeur avec l\'adresse MAC la plus basse est elu', 'Le routeur avec la priorite OSPF la plus haute est elu, en cas d\'egalite, le Router ID le plus haut l\'emporte', 'Le premier routeur a demarrer sur le segment est elu', 'Le routeur avec le cout OSPF le plus bas est elu'], correct: 1, explanation: 'L\'election du DR se fait en comparant la priorite OSPF (0-255, defaut 1) : la plus haute gagne. En cas d\'egalite, le Router ID le plus haut l\'emporte. Une priorite de 0 empeche un routeur de devenir DR ou BDR. L\'election n\'est pas premptive : un nouveau routeur avec une meilleure priorite ne detrône pas le DR actuel.' },
    { id: 'q20_8', question: 'Quels types de LSA sont presents dans une aire OSPF single-area ?', options: ['Uniquement les LSA Type 5 (External)', 'Les LSA Type 1 (Router LSA) et Type 2 (Network LSA)', 'Uniquement les LSA Type 3 (Summary)', 'Les LSA Type 4 et Type 7'], correct: 1, explanation: 'Dans une aire single-area, on trouve principalement les LSA Type 1 (Router LSA, genere par chaque routeur decrivant ses liens) et LSA Type 2 (Network LSA, genere par le DR sur les segments multi-acces). Les LSA Type 3, 4, 5 et 7 apparaissent dans les topologies multi-aires.' },
    { id: 'q20_9', question: 'Quelle commande configure une interface comme passive dans OSPF pour ne pas envoyer de Hello ?', options: ['no ospf hello', 'passive-interface G0/0', 'ip ospf passive', 'ospf suppress-hello G0/0'], correct: 1, explanation: 'La commande "passive-interface [interface]" sous le processus OSPF empeche l\'envoi de paquets Hello sur cette interface. Le reseau de l\'interface est toujours annonce dans OSPF, mais aucune adjacence ne peut se former. C\'est utilise sur les interfaces LAN connectees aux utilisateurs finaux pour economiser des ressources.' },
    { id: 'q20_10', question: 'Quelle est la condition indispensable pour que deux routeurs OSPF deviennent voisins ?', options: ['Ils doivent avoir le meme Router ID', 'Ils doivent etre dans la meme aire, avec les memes intervalles Hello/Dead, le meme type de reseau et le meme sous-reseau', 'Ils doivent utiliser le meme process-id OSPF', 'Ils doivent avoir la meme priorite OSPF'], correct: 1, explanation: 'Pour former une adjacence OSPF, les routeurs doivent partager : la meme aire, les memes intervalles Hello et Dead, le meme type de reseau (broadcast, point-to-point...), le meme sous-reseau, et un MTU compatible. La meme zone d\'authentification est aussi requise si configuree. Le process-id peut etre different.' },
  ],
  21: [
    { id: 'q21_1', question: 'Quelle est la difference fondamentale entre un protocole a vecteur de distance et un protocole a etat de lien ?', options: ['Les protocoles a vecteur de distance sont plus rapides que ceux a etat de lien', 'Un protocole a vecteur de distance partage sa table de routage avec ses voisins directs, tandis qu\'un protocole a etat de lien diffuse l\'etat de ses liens a tous les routeurs de l\'aire', 'Les protocoles a etat de lien ne supportent pas le routage classless', 'Il n\'y a pas de difference significative entre les deux types'], correct: 1, explanation: 'Les protocoles a vecteur de distance (RIP, EIGRP) envoient periodiquement leur table de routage complete (ou partielle) a leurs voisins directs. Les protocoles a etat de lien (OSPF, IS-IS) diffusent des LSA decrivant l\'etat de leurs interfaces a tous les routeurs de l\'aire, qui construisent une carte complete du reseau.' },
    { id: 'q21_2', question: 'Quelle est la distance administrative par defaut de RIP ?', options: ['90', '110', '120', '170'], correct: 2, explanation: 'RIP a une AD de 120. Pour comparaison : Connected=0, Static=1, EIGRP interne=90, OSPF=110, IS-IS=115, RIP=120, EIGRP externe=170, iBGP=200. La valeur elevee de RIP signifie qu\'il est moins prefere que OSPF ou EIGRP quand plusieurs protocoles apprennent une route vers la meme destination.' },
    { id: 'q21_3', question: 'Quel protocole de routage est considere comme un hybride entre vecteur de distance et etat de lien ?', options: ['OSPF', 'RIP', 'EIGRP', 'BGP'], correct: 2, explanation: 'EIGRP (Enhanced Interior Gateway Routing Protocol) est souvent decrit comme un protocole hybride ou "advanced distance vector". Il utilise un vecteur de distance mais avec des mecanismes avances comme l\'algorithme DUAL, les mises a jour incrementales (pas d\'envoi periodique de la table complete) et le maintien d\'une table topologique avec des routes de secours (feasible successors).' },
    { id: 'q21_4', question: 'Quelle est la principale limitation du protocole RIP ?', options: ['Il ne supporte pas le routage IPv6', 'Il est limite a 15 sauts maximum, un reseau a 16 sauts est considere comme inatteignable', 'Il ne peut fonctionner que sur des reseaux Ethernet', 'Il ne supporte pas l\'authentification'], correct: 1, explanation: 'RIP utilise le nombre de sauts (hop count) comme seule metrique, avec un maximum de 15. Un reseau a 16 sauts est considere comme "infinity" (inatteignable). Cette limitation rend RIP inadapte aux grands reseaux. De plus, RIP converge lentement et ne prend pas en compte la bande passante des liens.' },
    { id: 'q21_5', question: 'Quel protocole de routage est utilise pour le routage inter-AS (entre systemes autonomes) sur Internet ?', options: ['OSPF', 'EIGRP', 'RIP', 'BGP (Border Gateway Protocol)'], correct: 3, explanation: 'BGP (Border Gateway Protocol) est le protocole de routage utilise entre les systemes autonomes (AS) sur Internet. C\'est un protocole de type "path vector" qui utilise des attributs pour selectionner les meilleurs chemins. Contrairement aux IGP (OSPF, EIGRP, RIP) utilises a l\'interieur d\'un AS, BGP est un EGP (Exterior Gateway Protocol).' },
    { id: 'q21_6', question: 'Quelle metrique EIGRP utilise-t-il par defaut pour calculer le meilleur chemin ?', options: ['Le nombre de sauts uniquement', 'La bande passante et le delai par defaut (la charge et la fiabilite sont disponibles mais inactives)', 'Le cout base sur la bande passante de reference', 'Le nombre de liens traverses'], correct: 1, explanation: 'EIGRP utilise une metrique composite basee par defaut sur la bande passante minimale et le delai cumule du chemin. Les parametres K1 (bandwidth) et K3 (delay) sont actifs par defaut (K1=1, K3=1). La charge (K2) et la fiabilite (K4, K5) sont disponibles mais inactives (=0). Cela offre une metrique plus precise que le simple hop count de RIP.' },
    { id: 'q21_7', question: 'Qu\'est-ce qu\'un systeme autonome (AS) dans le contexte du routage ?', options: ['Un routeur qui fonctionne sans intervention humaine', 'Un ensemble de reseaux et routeurs sous une meme administration, utilisant une politique de routage commune', 'Un protocole de routage qui s\'auto-configure', 'Un serveur qui distribue automatiquement les routes'], correct: 1, explanation: 'Un systeme autonome (AS) est un ensemble de reseaux IP et de routeurs geres par une seule entite administrative (FAI, entreprise, universite) qui applique une politique de routage interne coherente. Chaque AS a un numero unique (ASN). Les IGP fonctionnent a l\'interieur d\'un AS, BGP entre les AS.' },
    { id: 'q21_8', question: 'Quel est l\'avantage principal des protocoles a etat de lien par rapport aux protocoles a vecteur de distance ?', options: ['Ils utilisent moins de memoire et de CPU', 'Ils convergent plus rapidement et ont une vision complete de la topologie du reseau, evitant les boucles de routage', 'Ils sont plus simples a configurer', 'Ils ne necessitent pas d\'adresse IP sur les interfaces'], correct: 1, explanation: 'Les protocoles a etat de lien (OSPF, IS-IS) offrent une convergence rapide car chaque routeur possede une carte complete du reseau (LSDB). Ils utilisent l\'algorithme SPF pour calculer des chemins sans boucle. Les protocoles a vecteur de distance convergent plus lentement et peuvent souffrir de boucles temporaires (count to infinity).' },
    { id: 'q21_9', question: 'Quelle est la distance administrative par defaut d\'une route apprise par eBGP ?', options: ['20', '90', '110', '200'], correct: 0, explanation: 'eBGP (external BGP, entre AS differents) a une AD de 20, ce qui la rend preferee a tous les IGP (EIGRP=90, OSPF=110, RIP=120). iBGP (internal BGP, au sein du meme AS) a une AD de 200, ce qui la rend moins preferee que les IGP. Cela garantit que les routes internes sont preferees aux routes apprises d\'autres AS via iBGP.' },
    { id: 'q21_10', question: 'Quel mecanisme RIP utilise-t-il pour prevenir les boucles de routage ?', options: ['L\'algorithme SPF de Dijkstra', 'Le split horizon, la route poisoning et le holddown timer', 'Les LSA et la base de donnees topologique', 'L\'algorithme DUAL avec les feasible successors'], correct: 1, explanation: 'RIP utilise plusieurs mecanismes anti-boucle : Split Horizon (ne pas renvoyer une route sur l\'interface par laquelle elle a ete apprise), Route Poisoning (annoncer une route en metrique infinie = 16), Poison Reverse (repondre avec metrique infinie) et Holddown Timer (attendre avant d\'accepter une route degradee). Malgre ces mecanismes, la convergence reste lente.' },
  ],
}
